"use strict";parserFactory.register("zirusmusings.com",()=>new ZirusMusingsParser),parserFactory.register("zirusmusings.net",()=>new ZirusMusingsParser);class ZirusMusingsParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=(await HttpClient.wrapFetch(t.baseURI)).responseXML.querySelector("#__NEXT_DATA__").innerHTML,r=JSON.parse(e).props.pageProps.data.volumes;return r=r.map(t=>t.chapters).map(t=>(t[0].newArc=t[0].volumeTitle,t)),r=r.flatMap(t=>t).filter(t=>null!=t.published),r.map(t=>({sourceUrl:"https://www.zirusmusings.net/series/"+t.series+"/"+t.chapter,title:t.title,newArc:t.newArc}))}async loadEpubMetaInfo(t){let e=(await HttpClient.wrapFetch(t.baseURI)).responseXML.querySelector("#__NEXT_DATA__").innerHTML,r=JSON.parse(e).props.pageProps.data;this.title=r?.name,this.author=r?.author,this.description=r?.summary,this.img=null!=r?.cover?"https://www.zirusmusings.net"+r?.cover:""}extractTitleImpl(){return null!=this.title?this.title:""}extractAuthor(){return null!=this.author?this.author:""}extractDescription(){return null!=this.description?this.description.trim():""}findCoverImageUrl(){return this.img}findContent(t){return Parser.findConstrutedContent(t)}async fetchChapter(t){let e=(await HttpClient.wrapFetch(t)).responseXML.querySelector("#__NEXT_DATA__").innerHTML,r=JSON.parse(e);return this.buildChapter(r.props.pageProps,t)}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e),s=r.dom.createElement("h1");s.textContent=t.data.title?t.data.title:"Chapter "+t.data.chapter,r.content.appendChild(s);let i=util.sanitize(t.content);return util.moveChildElements(i.body,r.content),r.dom}}